const xml = $input.item.json.data || $input.item.json;
const xmlStr = typeof xml === 'string' ? xml : JSON.stringify(xml);

// Extract <item> blocks
const items = [];
const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
let match;
while ((match = itemRegex.exec(xmlStr)) !== null && items.length < 6) {
  const block = match[1];
  const get = (tag) => {
    const m = block.match(new RegExp('<' + tag + '[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/' + tag + '>|<' + tag + '[^>]*>([^<]*)<\/' + tag + '>', 'i'));
    return m ? (m[1] || m[2] || '').trim() : '';
  };
  items.push({
    title: get('title'),
    description: get('description'),
    link: get('link'),
    pubDate: get('pubDate')
  });
}

// Filter relevant to data/AI/engineering
const keywords = ['ai', 'machine learning', 'data', 'model', 'llm', 'gemini', 'python', 'cloud', 'automation', 'engineering'];
const scored = items.map(item => {
  const text = (item.title + ' ' + item.description).toLowerCase();
  const score = keywords.reduce((s, kw) => s + (text.includes(kw) ? 1 : 0), 0);
  return { ...item, score };
}).sort((a, b) => b.score - a.score);

const selected = scored[0];
if (!selected || !selected.title) throw new Error('No relevant RSS items found');

return {
  topic_title: selected.title,
  topic_description: selected.description,
  topic_link: selected.link,
  topic_date: selected.pubDate,
  source: 'Hacker News'
};

const config = $('⚙️ Configuración').item.json;
const topic = $('🔧 Parsear RSS').item.json;
const art = $input.item.json; // ya viene parseado

const today = new Date().toISOString().split('T')[0];
const filename = `${today}-${art.output.slug}.md`;

const fileContent = `---\nslug: ${art.slug}\ndate: ${today}\n---\n\n${art.content_markdown_es}\n`;

return {
  ...art,
  filename,
  date: today,
  github_file_path: `cv/content/posts/${filename}`,
  github_file_content_base64: Buffer.from(fileContent, 'utf8').toString('base64'),
  canonical_url: `https://mgobeaalcoba.github.io/blog/${art.output.slug}/`,
  github_pat: config.github_pat,
  devto_api_key: config.devto_api_key,
  supabase_service_key: config.supabase_service_key
};

const art = $('🔧 Parsear Artículo').item.json.output;
const supabaseResult = $input.item.json;

// supabaseResult is the newly created blog_post row
const newPost = Array.isArray(supabaseResult) ? supabaseResult[0] : supabaseResult;
const postId = newPost?.id;
if (!postId) throw new Error('Supabase insert did not return an ID. Response: ' + JSON.stringify(supabaseResult));

// Prepare tags for batch insert
const tagsPayload = art.tags.map(tag => ({
  post_id: postId,
  tag: tag.toLowerCase().replace(/[^a-z0-9]/g, '')
})).filter(t => t.tag.length > 0);

return {
  post_id: postId,
  tags_payload: tagsPayload,
  tags_payload_json: JSON.stringify(tagsPayload),
  slug: art.slug,
  title_en: art.title_en,
  canonical_url: art.canonical_url,
  content_markdown_en: art.content_markdown_en,
  tags: art.tags,
  devto_api_key: art.devto_api_key,
  supabase_service_key: art.supabase_service_key
};

