parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "slug": {
      "type": "string",
      "description": "URL-friendly English slug, max 6 words, lowercase, hyphens only"
    },
    "title_es": {
      "type": "string",
      "description": "Título atractivo en español, máximo 70 caracteres"
    },
    "title_en": {
      "type": "string",
      "description": "Attractive English title, maximum 70 characters"
    },
    "excerpt_es": {
      "type": "string",
      "description": "Resumen en español de 150-180 caracteres que invite a leer el artículo"
    },
    "excerpt_en": {
      "type": "string",
      "description": "English summary of 150-180 characters that invites reading the full article"
    },
    "category": {
      "type": "string",
      "enum": ["data-engineering", "machine-learning", "ai-tools", "python", "bigquery"],
      "description": "Article category, must be exactly one of the enum values"
    },
    "tags": {
      "type": "array",
      "items": { "type": "string" },
      "minItems": 2,
      "maxItems": 4,
      "description": "Lowercase tags, no spaces, no special characters"
    },
    "read_time": {
      "type": "string",
      "description": "Estimated read time, e.g. '8 min'"
    },
    "content_markdown_es": {
      "type": "string",
      "description": "Full article in Spanish, 1500-2500 words, markdown format, no frontmatter"
    },
    "content_markdown_en": {
      "type": "string",
      "description": "Full article in English, 1500-2500 words, markdown format, no frontmatter"
    }
  },
  "required": [
    "slug",
    "title_es",
    "title_en",
    "excerpt_es",
    "excerpt_en",
    "category",
    "tags",
    "read_time",
    "content_markdown_es",
    "content_markdown_en"
  ]
}
